package cli

import (
	"fmt"
	"os"
	"path/filepath"

	"github.com/jdbencardinop/tesseraworkspaces/internal"
	"github.com/spf13/cobra"
)

func addCmd() *cobra.Command {
	return &cobra.Command{
		Use:   "add <feature>",
		Short: "Create a feature workspace",
		Args:  cobra.ExactArgs(1),
		Run: func(cmd *cobra.Command, args []string) {
			feature := args[0]
			root := internal.FeaturePath(feature)

			wsRoot := internal.TwsRoot()
			internal.Must(os.MkdirAll(filepath.Join(wsRoot, ".tws-workspace"), 0755))
			internal.Must(os.MkdirAll(filepath.Join(root, "worktrees"), 0755))
			internal.Must(os.WriteFile(filepath.Join(root, "FEATURE.md"), []byte("# "+feature+"\n"), 0644))
			internal.Must(os.WriteFile(filepath.Join(root, "CLAUDE.local.md"), []byte("# "+feature+" - CLAUDE shared context\n"), 0644))

			fmt.Println("Feature added:", feature)
		},
	}
}

package cli

import (
	"fmt"
	"os"

	"github.com/jdbencardinop/tesseraworkspaces/internal"
	"github.com/spf13/cobra"
)

func archiveCmd() *cobra.Command {
	return &cobra.Command{
		Use:   "archive <feature> <branch>",
		Short: "Remove worktree from disk, keep branch ref",
		Args:  cobra.ExactArgs(2),
		Run: func(cmd *cobra.Command, args []string) {
			internal.RequireTool("git")

			feature := args[0]
			branch := args[1]

			featurePath := internal.FeaturePath(feature)

			stack, err := internal.LoadStack(featurePath)
			if err != nil || !internal.HasBranch(stack, branch) {
				fmt.Printf("Branch %q not found in feature %q stack\n", branch, feature)
				os.Exit(1)
			}

			path := internal.WorktreePath(feature, branch)

			if _, err := os.Stat(path); os.IsNotExist(err) {
				fmt.Printf("Already archived: %s\n", branch)
				return
			}

			err = internal.Run("git", "worktree", "remove", path)
			if err != nil {
				err = internal.Run("git", "worktree", "remove", "--force", path)
				if err != nil {
					fmt.Printf("Error removing worktree: %v\n", err)
					os.Exit(1)
				}
			}

			_ = internal.RunSilent("git", "worktree", "prune")

			fmt.Printf("Archived: %s (branch preserved, restore with: tws new %s %s)\n", branch, feature, branch)
		},
	}
}

package cli

import (
	"fmt"
	"os"

	"github.com/jdbencardinop/tesseraworkspaces/internal"
	"github.com/spf13/cobra"
)

func deleteCmd() *cobra.Command {
	return &cobra.Command{
		Use:     "delete <feature>",
		Aliases: []string{"rm"},
		Short:   "Remove feature and all worktrees",
		Args:    cobra.ExactArgs(1),
		Run: func(cmd *cobra.Command, args []string) {
			internal.RequireTool("git")

			feature := args[0]
			featurePath := internal.FeaturePath(feature)

			if _, err := os.Stat(featurePath); os.IsNotExist(err) {
				fmt.Printf("Feature not found: %s\n", feature)
				os.Exit(1)
			}

			stack, err := internal.LoadStack(featurePath)
			if err == nil {
				for _, entry := range stack.Branches {
					path := internal.WorktreePath(feature, entry.Name)
					if _, err := os.Stat(path); os.IsNotExist(err) {
						fmt.Printf("  Worktree already removed: %s\n", entry.Name)
						continue
					}
					err := internal.Run("git", "worktree", "remove", "--force", path)
					if err != nil {
						fmt.Printf("  Warning: failed to remove worktree %s: %v\n", entry.Name, err)
					} else {
						fmt.Printf("  Removed worktree: %s\n", entry.Name)
					}
				}
			}

			_ = internal.Run("git", "worktree", "prune")

			if err := os.RemoveAll(featurePath); err != nil {
				fmt.Printf("Error removing feature directory: %v\n", err)
				os.Exit(1)
			}

			fmt.Printf("Feature deleted: %s (branches preserved in git)\n", feature)
		},
	}
}

package cli

import (
	"fmt"
	"os"
	"path/filepath"

	skills "github.com/jdbencardinop/tesseraworkspaces/assets/skills"
	"github.com/spf13/cobra"
)

func initCmd() *cobra.Command {
	var agent string
	var force bool

	cmd := &cobra.Command{
		Use:   "init",
		Short: "Install agent skills (claude, copilot)",
		Run: func(cmd *cobra.Command, args []string) {
			installed := 0

			if agent == "" || agent == "claude" {
				if installFile(".claude/skills/tesseraworkspaces/SKILL.md", skills.ClaudeSkill, force) {
					installed++
				}
			}

			if agent == "" || agent == "copilot" {
				if installFile(".github/prompts/tws.prompt.md", skills.CopilotSkill, force) {
					installed++
				}
			}

			if agent != "" && agent != "claude" && agent != "copilot" {
				fmt.Printf("Unknown agent: %s (supported: claude, copilot)\n", agent)
				os.Exit(1)
			}

			if installed == 0 {
				fmt.Println("No files installed (already exist, use --force to overwrite)")
			} else {
				fmt.Printf("Installed %d skill file(s)\n", installed)
			}
		},
	}

	cmd.Flags().StringVar(&agent, "agent", "", "Target agent (claude, copilot)")
	cmd.Flags().BoolVar(&force, "force", false, "Overwrite existing files")

	return cmd
}

func installFile(relPath string, content []byte, force bool) bool {
	if _, err := os.Stat(relPath); err == nil && !force {
		fmt.Printf("  skip: %s (exists, use --force)\n", relPath)
		return false
	}

	dir := filepath.Dir(relPath)
	if err := os.MkdirAll(dir, 0755); err != nil {
		fmt.Printf("  error: could not create %s: %v\n", dir, err)
		return false
	}

	if err := os.WriteFile(relPath, content, 0644); err != nil {
		fmt.Printf("  error: could not write %s: %v\n", relPath, err)
		return false
	}

	fmt.Printf("  installed: %s\n", relPath)
	return true
}

package cli

import (
	"fmt"
	"os"
	"path/filepath"

	"github.com/jdbencardinop/tesseraworkspaces/internal"
	"github.com/spf13/cobra"
)

func listCmd() *cobra.Command {
	return &cobra.Command{
		Use:     "list",
		Aliases: []string{"ls"},
		Short:   "List features and branches",
		Args:    cobra.NoArgs,
		Run: func(cmd *cobra.Command, args []string) {
			wsRoot := internal.TwsRoot()

			if _, err := os.Stat(wsRoot); os.IsNotExist(err) {
				fmt.Println("No workspace found at:", wsRoot)
				return
			}

			entries, err := os.ReadDir(wsRoot)
			if err != nil {
				fmt.Printf("Error reading workspace: %v\n", err)
				os.Exit(1)
			}

			var features []string
			for _, e := range entries {
				if !e.IsDir() || e.Name() == ".tws-workspace" {
					continue
				}
				features = append(features, e.Name())
			}

			if len(features) == 0 {
				fmt.Println("No features found. Use 'tws add <feature>' to create one.")
				return
			}

			fmt.Printf("Workspace: %s\n\n", wsRoot)

			for _, feature := range features {
				featurePath := filepath.Join(wsRoot, feature)
				fmt.Printf("%s\n", feature)

				stack, err := internal.LoadStack(featurePath)
				if err == nil && len(stack.Branches) > 0 {
					for i, entry := range stack.Branches {
						wtPath := filepath.Join(featurePath, "worktrees", entry.Name)
						status := "active"
						if _, err := os.Stat(wtPath); os.IsNotExist(err) {
							if internal.IsPrunableWorktree(entry.Name) {
								status = "missing"
							} else {
								status = "archived"
							}
						}

						connector := "├──"
						if i == len(stack.Branches)-1 {
							connector = "└──"
						}
						fmt.Printf("  %s %s (base: %s) [%s]\n", connector, entry.Name, entry.Base, status)
					}
				} else {
					wtDir := filepath.Join(featurePath, "worktrees")
					wts, err := os.ReadDir(wtDir)
					if err != nil || len(wts) == 0 {
						fmt.Println("  (no branches)")
					} else {
						for i, wt := range wts {
							if !wt.IsDir() {
								continue
							}
							connector := "├──"
							if i == len(wts)-1 {
								connector = "└──"
							}
							fmt.Printf("  %s %s\n", connector, wt.Name())
						}
					}
				}
				fmt.Println()
			}
		},
	}
}

package cli

import (
	"fmt"
	"os"
	"os/exec"
	"strings"

	"github.com/jdbencardinop/tesseraworkspaces/internal"
	"github.com/spf13/cobra"
)

func newCmd() *cobra.Command {
	var base string
	var force bool

	cmd := &cobra.Command{
		Use:   "new <feature> <branch>",
		Short: "Create a worktree branch",
		Args:  cobra.ExactArgs(2),
		Run: func(cmd *cobra.Command, args []string) {
			internal.RequireTool("git")

			feature := args[0]
			branch := args[1]

			featurePath := internal.FeaturePath(feature)
			path := internal.WorktreePath(feature, branch)

			internal.Must(os.MkdirAll(featurePath, 0755))

			repoRoot, err := internal.MainRepoRoot()
			if err != nil {
				fmt.Println("Error: must be run from inside a git repository")
				os.Exit(1)
			}

			if internal.BranchExists(branch) {
				if isCheckedOut(branch) && !force {
					fmt.Printf("Warning: branch %q is already checked out in another worktree.\n", branch)
					fmt.Println("Use --force to check it out anyway.")
					os.Exit(1)
				}

				gitArgs := []string{"worktree", "add"}
				if force {
					gitArgs = append(gitArgs, "--force")
				}
				gitArgs = append(gitArgs, path, branch)
				internal.Must(internal.RunDir(repoRoot, "git", gitArgs...))
			} else {
				internal.Must(internal.RunDir(repoRoot, "git", "worktree", "add", path, "-b", branch))
			}

			stack, _ := internal.LoadStack(featurePath)
			if !internal.HasBranch(stack, branch) {
				stack.Branches = append(stack.Branches, internal.StackEntry{Name: branch, Base: base})
				internal.Must(internal.SaveStack(featurePath, stack))
			}

			fmt.Printf("Worktree created: %s (base: %s)\n", path, base)
		},
	}

	cmd.Flags().StringVar(&base, "base", "main", "Parent branch for stacking")
	cmd.Flags().BoolVarP(&force, "force", "f", false, "Force checkout of already checked-out branch")

	return cmd
}

// isCheckedOut checks if a branch is currently checked out in any worktree.
func isCheckedOut(branch string) bool {
	out, err := exec.Command("git", "worktree", "list", "--porcelain").Output()
	if err != nil {
		return false
	}
	for _, line := range strings.Split(string(out), "\n") {
		if strings.TrimSpace(line) == "branch refs/heads/"+branch {
			return true
		}
	}
	return false
}

package cli

import (
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"syscall"

	"github.com/jdbencardinop/tesseraworkspaces/internal"
	"github.com/spf13/cobra"
)

func openCmd() *cobra.Command {
	var useTmux bool
	var noTmux bool
	var noAgent bool

	cmd := &cobra.Command{
		Use:   "open <feature> <branch>",
		Short: "Open worktree and run agent",
		Args:  cobra.ExactArgs(2),
		Run: func(cmd *cobra.Command, args []string) {
			feature := args[0]
			branch := args[1]

			path := internal.WorktreePath(feature, branch)

			if _, err := os.Stat(path); os.IsNotExist(err) {
				fmt.Printf("Worktree not found: %s\n", path)
				os.Exit(1)
			}

			if noAgent {
				fmt.Printf("cd %s\n", path)
				fmt.Println("Run your agent manually from there.")
				return
			}

			// Resolve tmux preference
			tmux := useTmux
			if !cmd.Flags().Changed("tmux") && !noTmux {
				cfg := internal.LoadConfig()
				if cfg.UseTmux != nil {
					tmux = *cfg.UseTmux
				}
			}
			if noTmux {
				tmux = false
			}

			if tmux {
				openWithTmux(feature, branch, path)
			} else {
				openDirect(path)
			}
		},
	}

	cmd.Flags().BoolVar(&useTmux, "tmux", false, "Wrap in tmux session")
	cmd.Flags().BoolVar(&noTmux, "no-tmux", false, "Skip tmux even if configured")
	cmd.Flags().BoolVar(&noAgent, "no-agent", false, "Just print the worktree path")

	return cmd
}

func openDirect(path string) {
	cfg := internal.LoadConfig()
	agentCmd := cfg.GetAgentCommand()

	if isClaudeAgent(agentCmd) && hasClaudeSession(path) {
		agentCmd = agentCmd + " -c"
	}

	parts := strings.Fields(agentCmd)
	binary, err := exec.LookPath(parts[0])
	if err != nil {
		fmt.Printf("Error: agent %q not found in PATH\n", parts[0])
		os.Exit(1)
	}

	fmt.Printf("Opening: %s\nRunning: %s\n", path, agentCmd)

	if err := os.Chdir(path); err != nil {
		fmt.Printf("Error: could not cd to %s: %v\n", path, err)
		os.Exit(1)
	}

	if err := syscall.Exec(binary, parts, os.Environ()); err != nil {
		fmt.Printf("Error: could not exec %s: %v\n", agentCmd, err)
		os.Exit(1)
	}
}

func openWithTmux(feature, branch, path string) {
	internal.RequireTool("tmux")

	session := sanitizeSessionName(feature + "/" + branch)

	if sessionExists(session) {
		fmt.Printf("Attaching to existing session: %s\n", session)
		internal.Must(internal.Run("tmux", "attach", "-t", session))
		return
	}

	cfg := internal.LoadConfig()
	agentCmd := cfg.GetAgentCommand()

	if isClaudeAgent(agentCmd) && hasClaudeSession(path) {
		agentCmd = agentCmd + " -c"
	}

	fmt.Printf("Creating tmux session: %s\n", session)
	internal.Must(internal.Run("tmux", "new-session", "-d", "-s", session, "-c", path))

	fmt.Printf("Running: %s\n", agentCmd)
	internal.Must(internal.Run("tmux", "send-keys", "-t", session, agentCmd, "Enter"))

	internal.Must(internal.Run("tmux", "attach", "-t", session))
}

func sessionExists(name string) bool {
	cmd := exec.Command("tmux", "has-session", "-t", name)
	err := cmd.Run()
	return err == nil
}

func sanitizeSessionName(s string) string {
	r := strings.NewReplacer(".", "_", ":", "_", "/", "-")
	return r.Replace(s)
}

func isClaudeAgent(cmd string) bool {
	base := strings.Fields(cmd)[0]
	return base == "claude" || base == "claude-dev" || base == "cc"
}

func hasClaudeSession(workdir string) bool {
	home, err := os.UserHomeDir()
	if err != nil {
		return false
	}

	absPath, err := filepath.Abs(workdir)
	if err != nil {
		return false
	}

	encoded := strings.ReplaceAll(absPath, string(filepath.Separator), "-")
	projectDir := filepath.Join(home, ".claude", "projects", encoded)

	info, err := os.Stat(projectDir)
	if err != nil {
		return false
	}
	return info.IsDir()
}

